```class Solution {
public:
 vector<int> maxScoreIndices(vector<int>& nums) {
        int n = nums.size();
        vector<int> prefix_ones(n + 1, 0);
        for (int i = 0; i < n; ++i) {
            prefix_ones[i + 1] = prefix_ones[i] + nums[i];
        }
        int total_zeros = 0;
        int max_score = 0;
        for (int i = 0; i <= n; ++i) {
            int score = total_zeros + (n - i - (prefix_ones[n] - prefix_ones[i]));
            if (score > max_score) {
                max_score = score;
            }
            if (nums[i] == 0) {
                total_zeros++;
            }
        }
        vector<int> result;
        for (int i = 0; i <= n; ++i) {
            int score = total_zeros + (n - i - (prefix_ones[n] - prefix_ones[i]));
            if (score == max_score) {
                result.push_back(i);
            }
            if (i < n && nums[i] == 0) {
                total_zeros--;
            }
        }
        return result;
 }
};
